// MOCK AUTH
// ─────────────────────────────────────────────
const MOCK_USERS = [
  { email: "demo@neurolims.edu", password: "demo1234", name: "Guest" },
];
function mockLogin(e, p) {
  return new Promise((res, rej) =>
    setTimeout(() => {
      const u = MOCK_USERS.find((u) => u.email === e && u.password === p);
      u
        ? res({ user: { email: u.email, name: u.name } })
        : rej(new Error("Invalid email or password"));
    }, 700)
  );
}
function mockRegister(e, p, n) {
  return new Promise((res, rej) =>
    setTimeout(() => {
      if (MOCK_USERS.find((u) => u.email === e))
        return rej(new Error("Email already registered"));
      MOCK_USERS.push({ email: e, password: p, name: n });
      res({ user: { email: e, name: n } });
    }, 800)
  );
}

// ─────────────────────────────────────────────
// AUTH PAGE
// ─────────────────────────────────────────────
function AuthPage({ onAuth }) {
  const [tab, setTab] = useState("login");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [pass, setPass] = useState("");
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");

  const submit = async () => {
    setErr("");
    setLoading(true);
    try {
      const r =
        tab === "login"
          ? await mockLogin(email, pass)
          : await mockRegister(email, pass, name);
      onAuth(r.user);
    } catch (e) {
      setErr(e.message);
    }
    setLoading(false);
  };
  const demo = async () => {
    setLoading(true);
    try {
      const r = await mockLogin("demo@neurolims.edu", "demo1234");
      onAuth(r.user);
    } catch {}
    setLoading(false);
  };

  const feats = [
    {
      icon: "🧠",
      bg: "#fdecea",
      title: "Interactive Brain Atlas",
      desc: "External & internal views with clickable regions",
    },
    {
      icon: "🔬",
      bg: "#f1f8e9",
      title: "250M+ Research Papers",
      desc: "Live data from the OpenAlex database",
    },
    {
      icon: "📚",
      bg: "#fff8e1",
      title: "Save & Organise",
      desc: "Build your personal reference library",
    },
  ];

  return (
    <div className="auth-page">
      <div className="auth-left">
        <div className="auth-brand">
          <img
            src="data:image/png;base64,"
            alt="NeuroLIMS"
            className="auth-brand-logo"
            onError={(e) => (e.target.style.display = "none")}
          />
          <div className="auth-tagline">Neuroscience research for students</div>
        </div>
        <div className="auth-hero">
          <h1>
            Explore the brain.
            <br />
            <em>Discover</em> the science.
          </h1>
          <p>
            An interactive research tool connecting you to peer-reviewed
            neuroscience papers — organised by brain region.
          </p>
        </div>
        <div className="auth-features">
          {feats.map((f, i) => (
            <div
              key={i}
              className="auth-feat"
              style={{ animationDelay: `${i * 80}ms` }}
            >
              <div className="auth-feat-icon" style={{ background: f.bg }}>
                {f.icon}
              </div>
              <div className="auth-feat-text">
                <strong>{f.title}</strong>
                {f.desc}
              </div>
            </div>
          ))}
        </div>
      </div>
      <div className="auth-right">
        <div className="auth-card">
          <div className="auth-card-head">
            <div className="auth-card-title">
              {tab === "login" ? "Welcome back!" : "Create account"}
            </div>
            <div className="auth-card-sub">
              {tab === "login"
                ? "Sign in to access your research library"
                : "Join NeuroLIMS — it's free"}
            </div>
          </div>
          <div className="auth-tabs">
            <button
              className={`auth-tab ${tab === "login" ? "active" : ""}`}
              onClick={() => {
                setTab("login");
                setErr("");
              }}
            >
              Sign In
            </button>
            <button
              className={`auth-tab ${tab === "register" ? "active" : ""}`}
              onClick={() => {
                setTab("register");
                setErr("");
              }}
            >
              Register
            </button>
          </div>
          {tab === "register" && (
            <div className="auth-field">
              <label>Full Name</label>
              <input
                className="auth-input"
                placeholder="Your name"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>
          )}
          <div className="auth-field">
            <label>Email Address</label>
            <input
              className="auth-input"
              type="email"
              placeholder="you@university.edu"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && submit()}
            />
          </div>
          <div className="auth-field">
            <label>Password</label>
            <input
              className="auth-input"
              type="password"
              placeholder={
                tab === "register" ? "Min. 8 characters" : "Your password"
              }
              value={pass}
              onChange={(e) => setPass(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && submit()}
            />
          </div>
          {err && <div className="auth-error">⚠ {err}</div>}
          <button className="auth-submit" onClick={submit} disabled={loading}>
            {loading
              ? "⏳ Please wait…"
              : tab === "login"
              ? "Sign In →"
              : "Create Account →"}
          </button>
          <div className="auth-div">or</div>
          <button className="auth-demo" onClick={demo} disabled={loading}>
            🎓 Continue as Guest
          </button>
          <div className="auth-switch">
            {tab === "login" ? (
              <>
                Don't have an account?{" "}
                <a
                  onClick={() => {
                    setTab("register");
                    setErr("");
                  }}
                >
                  Register free
                </a>
              </>
            ) : (
              <>
                Already have an account?{" "}
                <a
                  onClick={() => {
                    setTab("login");
                    setErr("");
                  }}
                >
                  Sign in
                </a>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// BRAIN MAP — Image + SVG overlay
// ─────────────────────────────────────────────
function BrainMap({ selectedRegion, onSelect }) {
  const [view, setView] = useState("external");
  const [hovered, setHovered] = useState(null);
  const [tooltipPos, setTooltipPos] = useState(null);
  const wrapRef = useRef(null);

  const paths = BRAIN_PATHS[view];
  const visibleRegions = Object.keys(paths);

  const handleMouseMove = (e, regionId) => {
    const rect = wrapRef.current?.getBoundingClientRect();
    if (!rect) return;
    setTooltipPos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
    setHovered(regionId);
  };

  const handleClick = (regionId) => {
    onSelect((prev) => (prev === regionId ? null : regionId));
  };

  return (
    <div className="brain-main">
      <div className="brain-page-header">
        <h1>Brain Atlas</h1>
        <p>Click a region to explore its research</p>
      </div>

      {/* View toggle */}
      <div className="view-toggle">
        <button
          className={`view-btn ${view === "external" ? "active" : ""}`}
          onClick={() => {
            setView("external");
            onSelect(null);
          }}
        >
          🧠 External View
        </button>
        <button
          className={`view-btn ${view === "internal" ? "active" : ""}`}
          onClick={() => {
            setView("internal");
            onSelect(null);
          }}
        >
          🔬 Internal View
        </button>
      </div>

      {/* Brain image + SVG overlay */}
      <div
        className="brain-svg-wrap"
        ref={wrapRef}
        onMouseLeave={() => {
          setHovered(null);
          setTooltipPos(null);
        }}
      >
        {/* External image */}
        <img
          src={extBrainImg}
          alt="External brain"
          className="brain-img"
          style={{
            opacity: view === "external" ? 1 : 0,
            zIndex: view === "external" ? 1 : 0,
          }}
        />
        {/* Internal image */}
        <img
          src={intBrainImg}
          alt="Internal brain"
          className="brain-img"
          style={{
            opacity: view === "internal" ? 1 : 0,
            zIndex: view === "internal" ? 1 : 0,
          }}
        />

        {/* SVG overlay */}
        <svg
          className="brain-svg-overlay"
          viewBox={`0 0 ${SVG_SIZE} ${SVG_SIZE}`}
          style={{ zIndex: 2 }}
        >
          {visibleRegions.map((rid) => {
            const region = REGIONS[rid];
            const pd = paths[rid];
            if (!region || !pd) return null;
            const isSelected = selectedRegion === rid;
            const isHovered = hovered === rid;
            return (
              <path
                key={rid}
                className="region-hit-area"
                d={pd.path}
                fill={region.color}
                fillOpacity={isSelected ? 0.55 : isHovered ? 0.42 : 0.22}
                stroke={region.color}
                strokeWidth={isSelected ? 2.5 : isHovered ? 1.8 : 0.8}
                strokeOpacity={isSelected ? 0.9 : isHovered ? 0.7 : 0.4}
                onMouseMove={(e) => handleMouseMove(e, rid)}
                onMouseLeave={() => {
                  setHovered(null);
                  setTooltipPos(null);
                }}
                onClick={() => handleClick(rid)}
              />
            );
          })}
        </svg>

        {/* Tooltip */}
        {hovered && tooltipPos && REGIONS[hovered] && (
          <div
            className="region-tooltip"
            style={{ left: tooltipPos.x, top: tooltipPos.y }}
          >
            <span
              style={{
                display: "inline-block",
                width: 8,
                height: 8,
                borderRadius: "50%",
                background: REGIONS[hovered].color,
                marginRight: 6,
                verticalAlign: "middle",
              }}
            />
            {REGIONS[hovered].name}
          </div>
        )}
      </div>

      {/* Legend — filtered per view */}
      <div className="brain-legend">
        {(view === "internal"
          ? [
              "frontal",
              "paracentral",
              "precuneus",
              "cingulate",
              "cuneus",
              "cerebellum_int",
            ]
              .map((id) => REGIONS[id])
              .filter(Boolean)
          : Object.values(REGIONS).filter((r) => r.views.includes("external"))
        ).map((r) => (
          <div
            key={r.id}
            className={`legend-chip ${
              selectedRegion === r.id ? "active-chip" : ""
            }`}
            onClick={() => handleClick(r.id)}
          >
            <div className="legend-dot" style={{ background: r.color }} />
            {r.name}
          </div>
        ))}
      </div>
    </div>
  );
}

