// LEARN MORE MODAL
// ─────────────────────────────────────────────
function LearnMoreModal({ regionId, onClose }) {
  const region = REGIONS[regionId];
  const details = REGION_DETAILS[regionId];
  if (!region || !details) return null;

  return (
    <div className="modal-overlay" onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="modal-box">
        <div className="modal-header">
          <div className="modal-header-left">
            <span className="modal-category-tag">{region.category}</span>
            <div className="modal-title">{region.name}</div>
            <div className="modal-accent-bar" style={{ background: region.color }} />
          </div>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>

        <div className="modal-body">
          {/* Overview */}
          <div className="modal-section">
            <div className="modal-section-title">Overview</div>
            <p className="modal-desc">{details.overview}</p>
          </div>

          {/* Stats */}
          <div className="modal-section">
            <div className="modal-section-title">Key Statistics</div>
            <div className="modal-stats-grid">
              <div className="modal-stat-card">
                <div className="modal-stat-label">Neurons</div>
                <div className="modal-stat-val">{region.neurons}</div>
              </div>
              <div className="modal-stat-card">
                <div className="modal-stat-label">Firing Rate</div>
                <div className="modal-stat-val">{region.firingRate}</div>
              </div>
              <div className="modal-stat-card">
                <div className="modal-stat-label">Volume</div>
                <div className="modal-stat-val">{details.volume}</div>
              </div>
            </div>
          </div>

          {/* Key Facts */}
          <div className="modal-section">
            <div className="modal-section-title">Key Facts</div>
            <div className="modal-facts">
              {details.facts.map((f, i) => (
                <div key={i} className="modal-fact">
                  <span className="modal-fact-icon">{f.icon}</span>
                  <div className="modal-fact-text">
                    <strong>{f.title}</strong>
                    {f.text}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Connections */}
          <div className="modal-section">
            <div className="modal-section-title">Major Connections</div>
            <div className="modal-connections">
              {details.connections.map((c, i) => (
                <span key={i} className="modal-conn-chip">{c}</span>
              ))}
            </div>
          </div>

          {/* Clinical Relevance */}
          <div className="modal-section">
            <div className="modal-section-title">Clinical Relevance</div>
            <p className="modal-desc">{details.clinical}</p>
          </div>

          {/* Development */}
          <div className="modal-section" style={{ marginBottom: 0 }}>
            <div className="modal-section-title">Development</div>
            <p className="modal-desc">{details.development}</p>
          </div>
        </div>

        <div className="modal-footer">
          <button className="btn-red" style={{ flex: 1 }} onClick={onClose}>Close</button>
        </div>
      </div>
    </div>
  );
}

