function RegionDrawer({ regionId, onOpenResearch }) {
  const [showModal, setShowModal] = useState(false);
  const region = REGIONS[regionId];
  if (!region)
    return (
      <div className="region-drawer">
        <div className="drawer-empty">
          <div className="drawer-empty-inner">
            <img
              src="data:image/png;base64,"
              className="drawer-empty-img"
              alt=""
              onError={(e) => (e.target.style.display = "none")}
            />
            <p>
              Click any highlighted region on the brain to explore its anatomy
              and research.
            </p>
          </div>
        </div>
      </div>
    );
  return (
    <div className="region-drawer">
      <div className="drawer-accent" style={{ background: region.color }} />
      <div className="drawer-body">
        <span className="drawer-tag">{region.category}</span>
        <div className="drawer-title">{region.name}</div>
        <div className="drawer-desc">{region.desc}</div>
        <div className="drawer-stats">
          <div className="drawer-stat">
            <div className="drawer-stat-label">Neurons</div>
            <div className="drawer-stat-val">{region.neurons}</div>
          </div>
          <div className="drawer-stat">
            <div className="drawer-stat-label">Firing Rate</div>
            <div className="drawer-stat-val">{region.firingRate}</div>
          </div>
        </div>
        <div className="drawer-view-badge">
          {region.views
            .map((v) => (
              <span key={v}>
                {v === "external" ? "🧠 External" : "🔬 Internal"}
              </span>
            ))
            .reduce((a, b) => [a, " · ", b])}
        </div>
        <div className="drawer-actions">
          <button className="btn-red" onClick={() => onOpenResearch(regionId)}>
            <svg
              width="13"
              height="13"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2.5"
            >
              <circle cx="11" cy="11" r="8" />
              <line x1="21" y1="21" x2="16.65" y2="16.65" />
            </svg>
            Explore Research
          </button>
          <button className="btn-outline" onClick={() => setShowModal(true)}>
            <svg
              width="13"
              height="13"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
            >
              <circle cx="12" cy="12" r="10" />
              <path d="M12 16v-4M12 8h.01" />
            </svg>
            Learn More
          </button>
        </div>
      </div>
      {showModal && (
        <LearnMoreModal regionId={regionId} onClose={() => setShowModal(false)} />
      )}
    </div>
  );
}

// ─────────────────────────────────────────────
// PAPER CARD
// ─────────────────────────────────────────────
function PaperCard({ paper, index, onSave }) {
  const authors = (paper.authorships || [])
    .slice(0, 3)
    .map((a) => a.author?.display_name)
    .filter(Boolean);
  const journal = paper.primary_location?.source?.display_name;
  const doi = paper.doi;
  const href = doi
    ? doi.startsWith("http")
      ? doi
      : `https://doi.org/${doi}`
    : null;
  return (
    <div className="paper-card" style={{ animationDelay: `${index * 40}ms` }}>
      <div className="pc-top">
        <div className="pc-body">
          <div className="pc-title">{paper.title}</div>
          <div className="pc-tags">
            {paper.publication_year && (
              <span className="pc-tag yr">{paper.publication_year}</span>
            )}
            {paper.cited_by_count > 0 && (
              <span className="pc-tag ct">
                {paper.cited_by_count.toLocaleString()} cited
              </span>
            )}
            {paper.open_access?.is_oa && (
              <span className="pc-tag oa">Open Access</span>
            )}
            {journal && (
              <span className="pc-tag jr">
                {journal.length > 34 ? journal.slice(0, 34) + "…" : journal}
              </span>
            )}
          </div>
          {authors.length > 0 && (
            <div className="pc-authors">
              {authors.join(" · ")}
              {(paper.authorships || []).length > 3
                ? ` +${paper.authorships.length - 3} more`
                : ""}
            </div>
          )}
        </div>
        <div className="pc-actions">
          {href && (
            <a
              href={href}
              target="_blank"
              rel="noreferrer"
              style={{ textDecoration: "none" }}
            >
              <button className="pc-btn open">Open ↗</button>
            </a>
          )}
          <button className="pc-btn sav" onClick={() => onSave(paper)}>
            + Save
          </button>
        </div>
      </div>
      {paper.abstract && <div className="pc-abstract">{paper.abstract}</div>}
    </div>
  );
}

