// ─────────────────────────────────────────────
// RESEARCH PAGE
// ─────────────────────────────────────────────
function ResearchPage({ regionId: initialRegionId, onBack, onSave }) {
  const [regionId, setRegionId] = useState(initialRegionId || "frontal");
  const region = REGIONS[regionId] || REGIONS.frontal;
  const [kw, setKw] = useState("");
  const [activeKw, setActiveKw] = useState("");
  const [yr, setYr] = useState("all");
  const [tab, setTab] = useState("papers");
  const [papers, setPapers] = useState(DUMMY_PAPERS);
  const [studies, setStudies] = useState([]);
  const [pTotal, setPTotal] = useState(DUMMY_PAPERS.length);
  const [sTotal, setSTotal] = useState(0);
  const [pPg, setPPg] = useState(1);
  const [sPg, setSPg] = useState(1);
  const [pLoad, setPLoad] = useState(false);
  const [sLoad, setSLoad] = useState(false);
  const [pErr, setPErr] = useState(null);

  // fetchP accepts an explicit yrParam to avoid stale-closure bugs when the
  // year filter changes and we call fetchP before React re-renders.
  const fetchP = useCallback(
    async (k, pg, rid, yrParam) => {
      const r2 = REGIONS[rid || regionId] || REGIONS.frontal;
      const activeYr = yrParam !== undefined ? yrParam : yr;
      const ypv =
        activeYr !== "all" && activeYr !== "custom"
          ? `,publication_year:${activeYr}`
          : "";
      setPLoad(true);
      setPErr(null);
      try {
        const q = k.trim() ? `${r2.searchTerms} ${k}` : r2.searchTerms;
        const res = await fetch(
          `https://api.openalex.org/works?search=${encodeURIComponent(
            q
          )}&per_page=8&page=${pg}&sort=cited_by_count:desc&filter=has_abstract:true${ypv}&${MAIL}`
        );
        const d = await res.json();
        setPapers(d.results || []);
        setPTotal(d.meta?.count || 0);
      } catch {
        setPErr("Could not load papers. Showing local data.");
        setPapers(DUMMY_PAPERS);
        setPTotal(DUMMY_PAPERS.length);
      }
      setPLoad(false);
    },
    [regionId, yr]
  );

  const fetchS = useCallback(
    async (pg, rid, yrParam) => {
      const r2 = REGIONS[rid || regionId] || REGIONS.frontal;
      const activeYr = yrParam !== undefined ? yrParam : yr;
      const ypv =
        activeYr !== "all" && activeYr !== "custom"
          ? `,publication_year:${activeYr}`
          : "";
      setSLoad(true);
      try {
        const res = await fetch(
          `https://api.openalex.org/works?search=${encodeURIComponent(
            r2.studyTerms
          )}&per_page=8&page=${pg}&sort=publication_date:desc&filter=has_abstract:true,type:article${ypv}&${MAIL}`
        );
        const d = await res.json();
        setStudies(d.results || []);
        setSTotal(d.meta?.count || 0);
      } catch {}
      setSLoad(false);
    },
    [regionId, yr]
  );

  useEffect(() => {
    setPPg(1);
    setSPg(1);
    setKw("");
    setActiveKw("");
    setYr("all");
    fetchP("", 1, regionId, "all");
    fetchS(1, regionId, "all");
  }, [regionId]);

  // Client-side year filter — exact integer match, never mutates source arrays.
  // Uses publication_year (OpenAlex integer) or parses a date string as fallback.
  const targetYear = yr !== "all" && yr !== "custom" ? parseInt(yr, 10) : null;
  const filteredPapers =
    targetYear === null
      ? papers
      : papers.filter((p) => {
          const y =
            p.publication_year != null
              ? p.publication_year
              : parseInt(p.date?.match(/\d{4}/)?.[0], 10);
          return y === targetYear;
        });
  const filteredStudies =
    targetYear === null
      ? studies
      : studies.filter((p) => {
          const y =
            p.publication_year != null
              ? p.publication_year
              : parseInt(p.date?.match(/\d{4}/)?.[0], 10);
          return y === targetYear;
        });

  const doSearch = () => {
    setActiveKw(kw);
    setPPg(1);
    fetchP(kw, 1);
  };
  const clearKw = () => {
    setKw("");
    setActiveKw("");
    setPPg(1);
    fetchP("", 1);
  };

  const isLoad = tab === "papers" ? pLoad : sLoad;
  const items = tab === "papers" ? filteredPapers : filteredStudies;
  const total = tab === "papers" ? pTotal : sTotal;
  const pg = tab === "papers" ? pPg : sPg;
  const setPg = tab === "papers" ? setPPg : setSPg;
  const reload =
    tab === "papers" ? (p) => fetchP(activeKw, p) : (p) => fetchS(p);

  return (
    <div className="research-page">
      <div className="research-topbar">
        <div className="breadcrumb">
          <span onClick={onBack} style={{ cursor: "pointer" }}>
            Brain Atlas
          </span>
          <span className="sep">›</span>
          <div className="region-pill">
            <div className="region-dot" style={{ background: region.color }} />
            <span className="region-pill-name">{region.name}</span>
          </div>
          <span className="sep">›</span>
          <span className="cur">Research Explorer</span>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          {isLoad && (
            <div className="load-ind">
              <div className="load-dot" />
              Fetching papers…
            </div>
          )}
          <span
            style={{
              fontSize: "0.7rem",
              color: "var(--grey-4)",
              fontFamily: "var(--font-mono)",
            }}
          >
            OpenAlex · 250M+ works
          </span>
        </div>
      </div>
      <div className="research-body">
        <div className="filters-col">
          {/* ── Brain Region Selector ── */}
          <div className="filter-sect">
            <div className="filter-head">🧠 Brain Region</div>
            <div style={{ position: "relative" }}>
              <div
                style={{
                  position: "absolute",
                  left: 11,
                  top: "50%",
                  transform: "translateY(-50%)",
                  width: 9,
                  height: 9,
                  borderRadius: "50%",
                  background: REGIONS[regionId]?.color || "var(--red)",
                  pointerEvents: "none",
                  zIndex: 1,
                }}
              />
              <select
                className="filter-select"
                value={regionId}
                onChange={(e) => setRegionId(e.target.value)}
                style={{ paddingLeft: 28 }}
              >
                {Object.values(REGIONS).map((r) => (
                  <option key={r.id} value={r.id}>
                    {r.name} — {r.category}
                  </option>
                ))}
              </select>
            </div>
          </div>

          {/* ── Keywords ── */}
          <div className="filter-sect">
            <div className="filter-head">🔍 Keywords</div>
            <input
              className="filter-input"
              style={{ marginBottom: 8 }}
              placeholder={`e.g. "aging", "fMRI"`}
              value={kw}
              onChange={(e) => setKw(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && doSearch()}
            />
            <div
              style={{
                fontSize: "0.68rem",
                color: "var(--grey-4)",
                marginBottom: 6,
              }}
            >
              Quick add
            </div>
            <div className="chip-row">
              {QUICK_TERMS.map((t) => (
                <button
                  key={t}
                  className={`chip ${activeKw === t ? "chip-active" : ""}`}
                  onClick={() => {
                    setKw(t);
                    setActiveKw(t);
                    setPPg(1);
                    fetchP(t, 1);
                  }}
                >
                  {t}
                </button>
              ))}
            </div>
            {activeKw && (
              <div
                style={{
                  margin: "8px 0",
                  display: "flex",
                  alignItems: "center",
                  gap: 6,
                }}
              >
                <span style={{ fontSize: "0.7rem", color: "var(--grey-4)" }}>
                  Active:
                </span>
                <span
                  style={{
                    fontSize: "0.68rem",
                    background: "var(--red-light)",
                    color: "var(--red)",
                    border: "1px solid var(--red-mid)",
                    padding: "2px 8px",
                    borderRadius: 20,
                    fontFamily: "var(--font-mono)",
                    fontWeight: 600,
                  }}
                >
                  {activeKw}
                </span>
                <button
                  onClick={clearKw}
                  style={{
                    background: "none",
                    border: "none",
                    cursor: "pointer",
                    fontSize: "0.7rem",
                    color: "var(--grey-4)",
                  }}
                >
                  ✕
                </button>
              </div>
            )}
            <button
              className="btn-search-full"
              onClick={doSearch}
              disabled={pLoad}
            >
              <svg
                width="12"
                height="12"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2.5"
              >
                <circle cx="11" cy="11" r="8" />
                <line x1="21" y1="21" x2="16.65" y2="16.65" />
              </svg>
              Search Papers
            </button>
          </div>

          {/* ── Year Filter ── */}
          <div className="filter-sect">
            <div className="filter-head">📅 Year Filter</div>
            <select
              className="filter-select"
              value={yr === "custom" ? "custom" : yr}
              onChange={(e) => {
                const v = e.target.value;
                setYr(v);
                if (v !== "custom") {
                  setPPg(1);
                  setSPg(1);
                  // Pass v directly so the API call uses the NEW year immediately,
                  // not the stale yr from the closure before re-render.
                  fetchP(activeKw, 1, undefined, v);
                  fetchS(1, undefined, v);
                }
              }}
            >
              <option value="all">All years</option>
              {[
                "2026",
                "2025",
                "2024",
                "2023",
                "2022",
                "2021",
                "2020",
                "2019",
                "2018",
              ].map((y) => (
                <option key={y} value={y}>
                  {y}
                </option>
              ))}
              <option value="custom">Custom year…</option>
            </select>
            {targetYear !== null && (
              <div className="paper-count-label">
                Showing {filteredPapers.length} of {papers.length} papers
              </div>
            )}
            {yr === "custom" && (
              <div style={{ marginTop: 8, display: "flex", gap: 6 }}>
                <input
                  className="filter-input"
                  placeholder="e.g. 2017"
                  maxLength={4}
                  style={{ flex: 1 }}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") {
                      const v = e.target.value.trim();
                      if (/^\d{4}$/.test(v)) {
                        setYr(v);
                        setPPg(1);
                        setSPg(1);
                        fetchP(activeKw, 1, undefined, v);
                        fetchS(1, undefined, v);
                      }
                    }
                  }}
                />
                <button
                  className="btn-red"
                  style={{ padding: "8px 12px", fontSize: "0.74rem" }}
                  onClick={(e) => {
                    const input = e.target
                      .closest(".filter-sect")
                      .querySelector("input");
                    const v = input?.value.trim();
                    if (v && /^\d{4}$/.test(v)) {
                      setYr(v);
                      setPPg(1);
                      setSPg(1);
                      fetchP(activeKw, 1, undefined, v);
                      fetchS(1, undefined, v);
                    }
                  }}
                >
                  Go
                </button>
              </div>
            )}
          </div>

          {/* ── Results count ── */}
          <div className="filter-sect">
            <div className="filter-head">📊 Results</div>
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: 8,
              }}
            >
              {[
                { l: "Papers", v: pTotal },
                { l: "Studies", v: sTotal },
              ].map((s) => (
                <div
                  key={s.l}
                  style={{
                    background: "var(--bg2)",
                    border: "1px solid var(--border-2)",
                    borderRadius: "var(--radius-sm)",
                    padding: "7px 10px",
                  }}
                >
                  <div
                    style={{
                      fontSize: "0.63rem",
                      textTransform: "uppercase",
                      letterSpacing: "0.06em",
                      color: "var(--grey-4)",
                      fontWeight: 700,
                      marginBottom: 2,
                    }}
                  >
                    {s.l}
                  </div>
                  <div
                    style={{
                      fontFamily: "var(--font-mono)",
                      fontSize: "0.88rem",
                      fontWeight: 700,
                      color: "var(--grey-1)",
                    }}
                  >
                    {s.v > 0 ? s.v.toLocaleString() + "+" : "—"}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
        <div className="results-col">
          <div className="res-tabs">
            <button
              className={`res-tab ${tab === "papers" ? "active" : ""}`}
              onClick={() => setTab("papers")}
            >
              📄 Research Papers{" "}
              <span className="tab-ct">
                {pTotal > 0 ? pTotal.toLocaleString() + "+" : "—"}
              </span>
            </button>
            <button
              className={`res-tab ${tab === "studies" ? "active" : ""}`}
              onClick={() => setTab("studies")}
            >
              🔬 Documented Studies{" "}
              <span className="tab-ct">
                {sTotal > 0 ? sTotal.toLocaleString() + "+" : "—"}
              </span>
            </button>
          </div>
          {!isLoad && items.length > 0 && (
            <div className="res-meta">
              <span className="res-meta-txt">
                {tab === "papers" ? "Sorted by citations" : "Sorted by date"} ·{" "}
                {total.toLocaleString()} results
              </span>
              {activeKw && (
                <span className="res-meta-kw" onClick={clearKw}>
                  {activeKw} ✕
                </span>
              )}
            </div>
          )}
          {isLoad ? (
            <div className="spinner-wrap">
              <div className="spinner" />
            </div>
          ) : pErr && tab === "papers" ? (
            <div className="empty-state">
              <div className="empty-icon">⚠️</div>
              <h3>Request Failed</h3>
              <p>{pErr}</p>
            </div>
          ) : items.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">🔬</div>
              <h3>No results</h3>
              <p>Try different keywords or year filter.</p>
            </div>
          ) : (
            <>
              {items.map((p, i) => (
                <PaperCard key={p.id} paper={p} index={i} onSave={onSave} />
              ))}
              <div className="pagination">
                <button
                  className="pg-btn"
                  disabled={pg === 1}
                  onClick={() => {
                    const n = pg - 1;
                    setPg(n);
                    reload(n);
                  }}
                >
                  ← Prev
                </button>
                <span className="pg-info">Page {pg}</span>
                <button
                  className="pg-btn"
                  onClick={() => {
                    const n = pg + 1;
                    setPg(n);
                    reload(n);
                  }}
                >
                  Next →
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

